#!/usr/bin/env -S npx ts-node -r tsconfig-paths/register
/**
 * Example: Upload a notebook to Databricks workspace
 *
 * This example demonstrates:
 * - Importing/uploading a notebook to workspace
 * - Creating workspace directories
 * - Setting notebook language and format
 * - Overwriting existing notebooks
 * - Getting notebook status
 *
 * Prerequisites:
 * - DATABRICKS_HOST environment variable
 * - Valid authentication (PAT, OAuth M2M, or other)
 *
 * Usage:
 *   npx ts-node examples/workspace/notebooks/upload-notebook.ts
 */

import {WorkspaceClient} from "@databricks/sdk-experimental";

async function main() {
    const client = new WorkspaceClient({});

    const notebookPath = `/Shared/sdk-notebook-${Date.now()}`;

    console.log(`Uploading notebook to: ${notebookPath}`);

    try {
        // Create a simple Python notebook content (base64 encoded)
        const notebookContent = `# Databricks notebook source
# MAGIC %md
# MAGIC # SDK Example Notebook
# MAGIC
# MAGIC This notebook was created by the Databricks SDK for JavaScript

# COMMAND ----------

print("Hello from Databricks SDK!")

# COMMAND ----------

# MAGIC %sql
# MAGIC SELECT "SQL works too!" as message

# COMMAND ----------

display(spark.range(10))
`;

        // Convert to base64
        const base64Content = Buffer.from(notebookContent).toString("base64");

        // Import the notebook
        await client.workspace.import({
            path: notebookPath,
            format: "SOURCE",
            language: "PYTHON",
            content: base64Content,
            overwrite: true,
        });

        console.log(`✓ Notebook uploaded successfully`);
        console.log(`  Path: ${notebookPath}`);
        console.log(`  URL: ${client.config.host}#notebook${notebookPath}`);

        // Get notebook status
        const status = await client.workspace.getStatus({
            path: notebookPath,
        });

        console.log(`\nNotebook Status:`);
        console.log(`  Path: ${status.path}`);
        console.log(`  Object Type: ${status.object_type}`);
        console.log(`  Language: ${status.language}`);
        console.log(
            `  Created At: ${status.created_at ? new Date(status.created_at).toISOString() : "N/A"}`
        );
        console.log(
            `  Modified At: ${status.modified_at ? new Date(status.modified_at).toISOString() : "N/A"}`
        );

        // Example: Import a notebook with different format (DBC)
        console.log(`\n--- Importing SQL notebook ---`);

        const sqlNotebookPath = `/Shared/sdk-sql-notebook-${Date.now()}`;
        const sqlContent = `-- Databricks notebook source
-- MAGIC %md
-- MAGIC # SQL Example Notebook

-- COMMAND ----------

SELECT current_timestamp() as now;

-- COMMAND ----------

SELECT explode(sequence(1, 10)) as number;
`;

        const sqlBase64 = Buffer.from(sqlContent).toString("base64");

        await client.workspace.import({
            path: sqlNotebookPath,
            format: "SOURCE",
            language: "SQL",
            content: sqlBase64,
            overwrite: true,
        });

        console.log(`✓ SQL notebook uploaded`);
        console.log(`  Path: ${sqlNotebookPath}`);

        // Cleanup: Delete the notebooks
        console.log(`\nCleaning up: deleting notebooks`);

        await client.workspace.delete({
            path: notebookPath,
            recursive: false,
        });
        console.log(`✓ Deleted ${notebookPath}`);

        await client.workspace.delete({
            path: sqlNotebookPath,
            recursive: false,
        });
        console.log(`✓ Deleted ${sqlNotebookPath}`);
    } catch (error) {
        console.error(`✗ Error:`, error);
        process.exit(1);
    }
}

main();
